# Exploratory: 3D hexahedral mesh on [−1, 1]³ with the resolution at the
# centre 5× higher than at the boundary, generated by Gmsh.
#
# Gmsh has no general hex-meshing algorithm for arbitrary domains — the
# practical route is to mesh with tetrahedra (which honour a size field
# well) and then subdivide each tet into hexes via the centroid trick.
# This is `Mesh.SubdivisionAlgorithm = 2`. Quality is mediocre (each cell
# is one of four hexes carved out of a single tet) but the size field is
# respected.
#
# The script generates the mesh, then plots two views:
#   1. The outer-boundary mesh in 3D (Axis3 wireframe).
#   2. A horizontal slice through z = 0 — the intersection of every hex
#      that straddles that plane.

using CairoMakie
using Gmsh: gmsh
using SixelTerm

# ----- parameters ----------------------------------------------------------

L        = 1.0
h_center = 0.10
h_edge   = 0.50         # ratio 5× — pushing for 10× makes the cell count blow up

# ----- Gmsh model ----------------------------------------------------------

gmsh.initialize()
try
    gmsh.option.setNumber("General.Terminal", 0)
    gmsh.clear()
    gmsh.model.add("cube")

    gmsh.model.occ.addBox(-L, -L, -L, 2L, 2L, 2L)
    gmsh.model.occ.synchronize()

    # Radial size field: linear interpolation along the L^∞ "distance from
    # origin" — max(|x|, |y|, |z|), which equals 1 on every face of the cube.
    fld = gmsh.model.mesh.field.add("MathEval")
    gmsh.model.mesh.field.setString(fld, "F",
        "$h_center + ($h_edge - $h_center) * max(max(abs(x), abs(y)), abs(z))")
    gmsh.model.mesh.field.setAsBackgroundMesh(fld)
    gmsh.option.setNumber("Mesh.MeshSizeFromPoints",         0)
    gmsh.option.setNumber("Mesh.MeshSizeFromCurvature",      0)
    gmsh.option.setNumber("Mesh.MeshSizeExtendFromBoundary", 0)

    # Mesh with tets that honour the size field, then subdivide each tet
    # into 4 hexes (= all-hex mesh).
    gmsh.option.setNumber("Mesh.Algorithm3D",         1)  # Delaunay
    gmsh.option.setNumber("Mesh.SubdivisionAlgorithm", 2)  # → all hexes
    gmsh.model.mesh.generate(3)

    # --- extract nodes ---------------------------------------------------
    node_tags, coords, _ = gmsh.model.mesh.getNodes()
    global N_nodes = length(node_tags)
    global xs = [coords[3i - 2] for i in 1:N_nodes]
    global ys = [coords[3i - 1] for i in 1:N_nodes]
    global zs = [coords[3i    ] for i in 1:N_nodes]
    tag_to_idx = Dict(node_tags[i] => i for i in 1:N_nodes)

    # --- extract hexes (Gmsh type 5: 8-node hex) -------------------------
    types, _, conn = gmsh.model.mesh.getElements(3)
    hi = findfirst(==(5), types)
    hi === nothing && error("Gmsh produced no hexahedral elements")
    hex_nodes = conn[hi]
    global N_hexes = length(hex_nodes) ÷ 8
    global hexes = [
        ntuple(k -> tag_to_idx[hex_nodes[8(h - 1) + k]], 8) for h in 1:N_hexes
    ]
finally
    gmsh.finalize()
end

println("nodes : $(N_nodes)")
println("hexes : $(N_hexes)")

# ----- hex geometry helpers ------------------------------------------------

# 12 edges of a hex in the Gmsh node ordering (1..4 bottom, 5..8 top).
const HEX_EDGES = (
    (1,2), (2,3), (3,4), (4,1),     # bottom face
    (5,6), (6,7), (7,8), (8,5),     # top face
    (1,5), (2,6), (3,7), (4,8),     # vertical
)
# 6 faces of a hex, each a 4-tuple of node-indices (in Gmsh canonical order).
const HEX_FACES = (
    (1,2,3,4),     # z-min
    (5,6,7,8),     # z-max
    (1,2,6,5),     # y-min
    (4,3,7,8),     # y-max
    (1,4,8,5),     # x-min
    (2,3,7,6),     # x-max
)

# A face is on the global boundary if all four of its nodes share one
# extremal coordinate (|x| ≈ L, etc.).
function boundary_face_planes(face_nodes)
    fx = (xs[face_nodes[1]], xs[face_nodes[2]], xs[face_nodes[3]], xs[face_nodes[4]])
    fy = (ys[face_nodes[1]], ys[face_nodes[2]], ys[face_nodes[3]], ys[face_nodes[4]])
    fz = (zs[face_nodes[1]], zs[face_nodes[2]], zs[face_nodes[3]], zs[face_nodes[4]])
    on(v, t) = all(abs.(v .- t) .< 1e-9)
    on(fx, -L) || on(fx, L) || on(fy, -L) || on(fy, L) || on(fz, -L) || on(fz, L)
end

# --- collect boundary edges ----------------------------------------------
bdry_edges = Set{NTuple{2,Int}}()
for h in hexes
    for f in HEX_FACES
        fnodes = (h[f[1]], h[f[2]], h[f[3]], h[f[4]])
        if boundary_face_planes(fnodes)
            # 4 edges of this quad face
            for k in 1:4
                a, b = fnodes[k], fnodes[mod1(k+1, 4)]
                push!(bdry_edges, (min(a,b), max(a,b)))
            end
        end
    end
end
println("boundary edges: $(length(bdry_edges))")

# ----- horizontal slice at z = 0 ------------------------------------------
# For each hex, intersect all 12 of its edges with the plane z = z_target.
# Hexes carved out of arbitrary tets do not have axis-aligned "top/bottom"
# faces, so we must consider every edge — not just the four "vertical"
# ones — and sort the resulting 3..6 crossing points by angle around their
# centroid to form a planar polygon.
function hex_slice_polygon(h, z_target)
    pts = NTuple{2, Float64}[]
    for (ka, kb) in HEX_EDGES
        a, b = h[ka], h[kb]
        za, zb = zs[a], zs[b]
        if (za - z_target) * (zb - z_target) < 0
            t = (z_target - za) / (zb - za)
            px = xs[a] + t * (xs[b] - xs[a])
            py = ys[a] + t * (ys[b] - ys[a])
            push!(pts, (px, py))
        end
    end
    return pts
end
function slice_polygons(z_target)
    polys = Vector{Vector{NTuple{2, Float64}}}()
    for h in hexes
        pts = hex_slice_polygon(h, z_target)
        if length(pts) ≥ 3
            cx = sum(p[1] for p in pts) / length(pts)
            cy = sum(p[2] for p in pts) / length(pts)
            sort!(pts; by = p -> atan(p[2] - cy, p[1] - cx))
            push!(polys, pts)
        end
    end
    return polys
end
slice = slice_polygons(0.0)
println("z=0 slice cells: $(length(slice))")

# ----- plot ----------------------------------------------------------------

fig = Figure(; size=(1100, 550))

# Left: 3D outer-boundary wireframe.
ax3 = Axis3(fig[1, 1];
            aspect=:data,
            title="Boundary mesh ($(N_hexes) hexes total)",
            xlabel="x", ylabel="y", zlabel="z",
            elevation=π/8, azimuth=π/4)
seg_x = Float64[];  seg_y = Float64[];  seg_z = Float64[]
for (a, b) in bdry_edges
    push!(seg_x, xs[a], xs[b], NaN)
    push!(seg_y, ys[a], ys[b], NaN)
    push!(seg_z, zs[a], zs[b], NaN)
end
lines!(ax3, seg_x, seg_y, seg_z; color=(:steelblue, 0.7), linewidth=0.5)

# Right: 2D slice at z = 0.
ax2 = Axis(fig[1, 2];
           aspect=DataAspect(),
           title="Slice at z = 0 ($(length(slice)) cells)",
           xlabel="x", ylabel="y")
for poly in slice
    px = [p[1] for p in poly];  push!(px, poly[1][1])
    py = [p[2] for p in poly];  push!(py, poly[1][2])
    lines!(ax2, px, py; color=(:steelblue, 0.7), linewidth=0.6)
end

display(fig)
nothing
